Javascript.isMandatory:
if (null != WP && null != WP.GetScreenProcess && null != WP.GetScreenProcess()) { var localNumber = WPU.getValue("/params/param[@name='xml']/ds/Warrant/LocalNumber");
				if (localNumber == "" || localNumber == null ) return false;
				return true; }

Javascript.isReadOnly:
/** When the warrant is a foreign warrant, this question should be visible. If there is a local number of the warrant, this will indicate a foreign warrant. **/
				if (null != WP && null != WP.GetScreenProcess && null != WP.GetScreenProcess()) { 
				var localNumber = WPU.getValue("/params/param[@name='xml']/ds/Warrant/LocalNumber");
				if (localNumber == "" || localNumber == null ) return true; }

Javascript.initialise:
/** The address is the selected warrant against party's address or if filled it is the other possession address	**/
			var partyAgainstNumber = WPU.getValue("/params/param[@name='xml']/WarrantReturn/PartyAgainstNumber");
			var def1Addr1 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant1/Address/Line[1]");
			var def2Addr1 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant2/Address/Line[1]");
			var partyAgainstAddr1 = "";
			if(partyAgainstNumber == 1) {
				partyAgainstAddr1 = def1Addr1; }
			else {
				partyAgainstAddr1 = def2Addr1; }
			var otherPossessAddr1 = WPU.getValue("/params/param[@name='xml']/ds/ManageCase/OtherPossessionAddress/Address/Line[1]");
			var possessAddr1 = "";
			if(otherPossessAddr1 != "") {
				possessAddr1 = otherPossessAddr1; }
			else {
				possessAddr1 = partyAgainstAddr1; }
			Services.setValue(PossessAdLine1.dataBinding, possessAddr1);
